import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';

// Rutas corregidas para los componentes que están en la misma carpeta 'components'
import Dashboard from './Dashboard';
// ✅ CORRECCIÓN DE RUTA Y CASO: InicioSesion.js -> inicioSesion.js (en disco)
// También verifica si realmente está en la carpeta 'components' o si está en 'src'
// Según tu error ".\src\components\inicioSesion.js", asumo que también está en 'components'
import InicioSesion from './inicioSesion'; // Asumiendo que es 'inicioSesion.js' en minúsculas en el disco
import Navbar from './navbar.jsx'; // Ahora está en la misma carpeta 'components'
import Header from './header';     // Ahora está en la misma carpeta 'components'

// Rutas corregidas para los componentes que están en la carpeta 'screens'
// Ahora App.js está en 'components', así que para ir a 'screens' debe subir un nivel (../)
import HomePage from '../screens/homePage';
import EmpresasPage from '../screens/empresasPage';
import ContactoPage from '../screens/contactoPage';
import HistoriaPage from '../screens/historiaPage';
import EditorEmpresasPage from '../screens/editorEmpresasPage';
import EditorUsuariosPage from '../screens/editorUsuariosPage';
import DashboardPage from '../screens/dashboardPage'; // Aunque no se use, corregimos la ruta
// ✅ CORRECCIÓN DE RUTA: panelEditorUsuarios está en la misma carpeta 'components'
import PanelEditorUsuarios from './panelEditorUsuarios';

function App() {
  const [loggedInUser, setLoggedInUser] = useState(null);
  const [showLoginModal, setShowLoginModal] = useState(false);

  // Cargar sesión del localStorage al iniciar
  useEffect(() => {
    const storedUser = localStorage.getItem('loggedInUser');
    if (storedUser) {
      try {
        const user = JSON.parse(storedUser);
        setLoggedInUser(user);
      } catch (error) {
        console.error("Error al parsear el usuario de localStorage:", error);
        localStorage.removeItem('loggedInUser'); // Limpiar si hay un error en el parseo
      }
    }
  }, []);

  // Función para manejar el login exitoso (recibe los datos del usuario)
  const handleLogin = (userData) => {
    console.log("Usuario ha iniciado sesión:", userData);
    localStorage.setItem('loggedInUser', JSON.stringify(userData));
    setLoggedInUser(userData);
    setShowLoginModal(false); // Cierra el modal después del login exitoso
  };

  // Función para cerrar la sesión
  const handleLogout = () => {
    localStorage.removeItem('loggedInUser');
    setLoggedInUser(null);
  };

  return (
    <Router> 
      <div style={styles.appContainer}>
        <Header />
        <Navbar loggedInUser={loggedInUser} onLogout={handleLogout} />

        <Routes>
          <Route path="/" element={<HomePage />} />
          <Route path="/empresas" element={<EmpresasPage />} />
          <Route path="/contacto" element={<ContactoPage />} />
          <Route path="/historia" element={<HistoriaPage />} />
          
          <Route 
            path="/dashboards" 
            element={loggedInUser ? <Dashboard usuario={loggedInUser} onLogout={handleLogout} /> : <div style={styles.unauthorized}>Acceso denegado. Inicia sesión.</div>} 
          />
          
          {loggedInUser && loggedInUser.id_rol === 1 && (
            <>
              <Route path="/editor-empresas" element={<EditorEmpresasPage />} />
              <Route path="/panel-usuarios" element={<PanelEditorUsuarios />} />
            </>
          )}

          {!loggedInUser && (
            <Route
              path="*"
              element={
                <div style={styles.bienvenida}>
                  <h1>Plataforma de Empresas</h1>
                  <p>Por favor, inicie sesión para acceder al sistema.</p>
                  <button style={styles.loginButton} onClick={() => setShowLoginModal(true)}>
                    Iniciar Sesión
                  </button>
                </div>
              }
            />
          )}
          {loggedInUser && loggedInUser.id_rol !== 1 && (
            <Route path="/editor-empresas" element={<div style={styles.unauthorized}>No tienes permisos para acceder a esta página.</div>} />
          )}
          {loggedInUser && loggedInUser.id_rol !== 1 && (
            <Route path="/panel-usuarios" element={<div style={styles.unauthorized}>No tienes permisos para acceder a esta página.</div>} />
          )}

        </Routes>
      </div>

      {showLoginModal && !loggedInUser && (
        <InicioSesion
          onLogin={handleLogin}
          onClose={() => setShowLoginModal(false)}
        />
      )}
    </Router>
  );
}

const styles = {
  appContainer: {
    fontFamily: "'Poppins', sans-serif",
  },
  bienvenida: {
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    height: 'calc(100vh - 120px)',
    textAlign: 'center',
  },
  loginButton: {
    padding: '12px 24px',
    fontSize: '16px',
    fontWeight: '600',
    backgroundColor: '#166D3B',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    textTransform: 'uppercase',
  },
  unauthorized: {
    padding: '50px',
    textAlign: 'center',
    fontSize: '1.5rem',
    color: '#FF4201',
    fontWeight: 'bold',
  }
};

export default App;
